    std::vector<int> w2;                           // 隨ｬ2 mixer 驥阪∩ (order-2 譁・ц x NIN)
    std::vector<int> w3;                           // 隨ｬ3 mixer 驥阪∩ (order-3 譁・ц x NIN)
