    std::vector<uint16_t> apm2;                    // 莠梧ｬ｡謗ｨ螳・(2048 譁・ц x 65 轤ｹ縲｜itpos莉倥″)
    std::vector<uint16_t> apm3;                    // 荳画ｬ｡謗ｨ螳・(1024 譁・ц x 65 轤ｹ縲…0ﾃ洋atch蠑ｷ蠎ｦ)
    std::vector<uint16_t> apm4;                    // 蝗帶ｬ｡謗ｨ螳・(2048 譁・ц x 65 轤ｹ縲…x[3]繝上ャ繧ｷ繝･+bitpos)
