    int apmShift = 7;                              // APM 譖ｴ譁ｰ繝ｬ繝ｼ繝・(繝励Ο繝輔ぃ繧､繝ｫ萓晏ｭ・
    int subShift = 24;                             // sub-mixer 譁・ц縺ｮ邏ｰ縺九＆ (繝励Ο繝輔ぃ繧､繝ｫ萓晏ｭ・
